def get_static_team(team_name):
    for league, teams in STATIC_TEAMS.items():
        if team_name in teams:
            return league
    return None

def all_static_team_names():
    names = []
    for teams in STATIC_TEAMS.values():
        names.extend(teams)
    return sorted(set(names))

def total_static_team_count():
    return sum(len(v) for v in STATIC_TEAMS.values())

